30	 * Returns an array of human-readable error strings (empty = valid).
31	 */
32	function validateField(fieldName, value, constraint) {
33	  const errs = [];
34	
35	  if (constraint.type === 'numeric') {
36	    // Accept numbers and numeric strings (e.g. route params are always strings)
37	    const num = Number(value);
38	    if (value === undefined || value === null || value === '' || !Number.isFinite(num)) {
39	      errs.push(`"${fieldName}" must be a numeric value`);
40	    } else if (!Number.isInteger(num) || num < 1) {
41	      errs.push(`"${fieldName}" must be a positive integer`);
42	    }
43	    return errs; // length checks don't apply to numerics
44	  }
45	
46	  if (constraint.type === 'string') {
