49	      return errs; // can't check length / pattern on a non-string
50	    }
51	    if (constraint.minLength !== undefined && value.length < constraint.minLength) {
52	      errs.push(`"${fieldName}" must be at least ${constraint.minLength} character(s) long`);
53	    }
54	    if (constraint.maxLength !== undefined && value.length > constraint.maxLength) {
55	      errs.push(`"${fieldName}" must not exceed ${constraint.maxLength} character(s)`);
56	    }
57	    if (constraint.pattern && !constraint.pattern.test(value)) {
