/**
 * Validation helper module.
 *
 * Each validator returns an array of error message strings.
 * An empty array means the value passed all checks.
 * Compose validators inside validateUserBody() to keep route handlers clean.
 */

// Follows RFC 5321/5322 practical subset; rejects obvious malformed addresses.
const EMAIL_REGEX =
  /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)+$/;

/**
 * Validate an `id` value (URL param or body field).
 * Accepts both numeric strings (from URL params) and numbers (from JSON bodies).
 *
 * Rules: required, must be a positive integer.
 *
 * @param {*} id
 * @returns {string[]} validation errors
 */
function validateId(id) {
  const errors = [];

  if (id === undefined || id === null || id === '') {
    errors.push('id is required');
    return errors;
  }

  const num = Number(id);
  if (!Number.isInteger(num) || num <= 0) {
    errors.push('id must be a positive integer');
  }

  return errors;
}

/**
 * Validate a `name` field.
 *
 * Rules: must be a string, 1–100 characters (whitespace-trimmed length counts).
 *
 * @param {*}       name
 * @param {boolean} required  Whether to report an error when the field is absent.
 * @returns {string[]} validation errors
 */
function validateName(name, required = true) {
  const errors = [];

  const absent = name === undefined || name === null || name === '';
  if (absent) {
    if (required) errors.push('name is required');
    return errors;
  }

  if (typeof name !== 'string') {
    errors.push('name must be a string');
    return errors;
  }

  const trimmed = name.trim();
  if (trimmed.length < 1) {
    errors.push('name must be at least 1 non-whitespace character');
  } else if (name.length > 100) {
    errors.push('name must be at most 100 characters');
  }

  return errors;
}

/**
 * Validate an `email` field.
 *
 * Rules: must be a string, match email format, at most 254 characters
 * (the maximum permitted by RFC 5321).
 *
 * @param {*}       email
 * @param {boolean} required  Whether to report an error when the field is absent.
 * @returns {string[]} validation errors
 */
function validateEmail(email, required = true) {
  const errors = [];

  const absent = email === undefined || email === null || email === '';
  if (absent) {
    if (required) errors.push('email is required');
    return errors;
  }

  if (typeof email !== 'string') {
    errors.push('email must be a string');
    return errors;
  }

  if (!EMAIL_REGEX.test(email)) {
    errors.push('email must be a valid email address');
  } else if (email.length > 254) {
    errors.push('email must be at most 254 characters');
  }

  return errors;
}

/**
 * Validate the body of a user create/update request.
 *
 * Combines name and email validators; returns all failures at once so the
 * caller can surface a complete list of problems in a single 400 response.
 *
 * @param {object}  body
 * @param {boolean} [options.requireAll=true]  Set to false for PATCH-style
 *                  partial updates where absent fields are acceptable.
 * @returns {string[]} validation errors (empty array = valid)
 */
function validateUserBody(body = {}, { requireAll = true } = {}) {
  return [
    ...validateName(body.name, requireAll),
    ...validateEmail(body.email, requireAll),
  ];
}

/**
 * Convenience wrapper: validate the `:id` route parameter.
 *
 * @param {object} params  Express req.params
 * @returns {string[]} validation errors
 */
function validateIdParam(params = {}) {
  return validateId(params.id);
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateUserBody,
  validateIdParam,
};

