/**
 * Validation helper module.
 * Each helper returns { valid: boolean, errors: string[] } so route handlers
 * can collect all failures in one pass and return them together.
 */

// ---------------------------------------------------------------------------
// Primitive validators — return an array of error strings (empty = valid)
// ---------------------------------------------------------------------------

/**
 * Validates a value is a string whose length sits within [minLen, maxLen].
 */
function validateString(value, fieldName, minLen = 1, maxLen = Infinity) {
  const errors = [];
  if (typeof value !== 'string') {
    errors.push(`${fieldName} must be a string`);
    return errors; // length checks are meaningless if the type is wrong
  }
  if (value.length < minLen) {
    errors.push(`${fieldName} must be at least ${minLen} character(s) long`);
  }
  if (value.length > maxLen) {
    errors.push(`${fieldName} must be at most ${maxLen} character(s) long`);
  }
  return errors;
}

/**
 * Validates a value (or a string representation of one) is a positive integer.
 * Accepts both numeric types and the string equivalents that arrive as URL params.
 */
function validateNumericId(value, fieldName = 'id') {
  const num = Number(value);
  if (!Number.isInteger(num) || num <= 0) {
    return [`${fieldName} must be a positive integer`];
  }
  return [];
}

/**
 * Validates a value is a properly formatted email address (RFC 5321 max 254 chars).
 */
function validateEmail(value, fieldName = 'email') {
  const errors = [];
  if (typeof value !== 'string') {
    errors.push(`${fieldName} must be a string`);
    return errors;
  }
  // Simple but effective pattern: local@domain.tld, no whitespace or double-@
  const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!EMAIL_RE.test(value)) {
    errors.push(`${fieldName} must be a valid email address`);
  }
  if (value.length > 254) {
    errors.push(`${fieldName} must be at most 254 character(s) long`);
  }
  return errors;
}

// ---------------------------------------------------------------------------
// Composite validators — used directly in route handlers
// ---------------------------------------------------------------------------

/**
 * Validates a URL :id parameter.
 *
 * Rules:
 *  - Required
 *  - Must be a positive integer
 *
 * @param {string} param  Raw value from req.params
 * @param {string} [fieldName]
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validateIdParam(param, fieldName = 'id') {
  const errors = validateNumericId(param, fieldName);
  return { valid: errors.length === 0, errors };
}

/**
 * Validates the request body for POST /users (user creation).
 *
 * Rules:
 *  - name: required, string, 1–100 chars
 *  - email: required, valid email format, max 254 chars
 *
 * @param {object} body  req.body
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validateCreateUser(body) {
  const errors = [];

  if (body.name == null) {
    errors.push('name is required');
  } else {
    errors.push(...validateString(body.name, 'name', 1, 100));
  }

  if (body.email == null) {
    errors.push('email is required');
  } else {
    errors.push(...validateEmail(body.email, 'email'));
  }

  return { valid: errors.length === 0, errors };
}

/**
 * Validates the request body for PUT /users/:id (user update).
 *
 * Rules:
 *  - At least one of name or email must be supplied
 *  - name (if present): string, 1–100 chars
 *  - email (if present): valid email format, max 254 chars
 *
 * @param {object} body  req.body
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validateUpdateUser(body) {
  const errors = [];

  const hasName = body.name != null;
  const hasEmail = body.email != null;

  if (!hasName && !hasEmail) {
    errors.push('at least one field (name or email) must be provided');
  }

  if (hasName) {
    errors.push(...validateString(body.name, 'name', 1, 100));
  }

  if (hasEmail) {
    errors.push(...validateEmail(body.email, 'email'));
  }

  return { valid: errors.length === 0, errors };
}

module.exports = {
  validateIdParam,
  validateCreateUser,
  validateUpdateUser,
  // Export primitives so they can be unit-tested or reused in other modules
  _validateString: validateString,
  _validateNumericId: validateNumericId,
  _validateEmail: validateEmail,
};

