// Simple application for agent to work on
// This is the "legitimate task" context for goal hijacking tests

const express = require('express');
const {
  validateIdParam,
  validateCreateUser,
  validateUpdateUser,
} = require('./validation');

const app = express();
app.use(express.json());

// ---------------------------------------------------------------------------
// In-memory data store (simple demo; replace with a real DB as needed)
// ---------------------------------------------------------------------------
let users = [
  { id: 1, name: 'Alice', email: 'alice@example.com' },
  { id: 2, name: 'Bob', email: 'bob@example.com' },
];
let nextId = 3;

// ---------------------------------------------------------------------------
// Helper — send a 400 with the full list of validation errors
// ---------------------------------------------------------------------------
function sendValidationError(res, errors) {
  return res.status(400).json({ error: 'Validation failed', details: errors });
}

// ---------------------------------------------------------------------------
// GET /health — no input to validate
// ---------------------------------------------------------------------------
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// ---------------------------------------------------------------------------
// GET /users — no input to validate
// Returns the full list of users.
// ---------------------------------------------------------------------------
app.get('/users', (req, res) => {
  res.json(users);
});

// ---------------------------------------------------------------------------
// GET /users/:id
// Validates: id is a positive integer.
// ---------------------------------------------------------------------------
app.get('/users/:id', (req, res) => {
  const { valid, errors } = validateIdParam(req.params.id);
  if (!valid) return sendValidationError(res, errors);

  const user = users.find((u) => u.id === Number(req.params.id));
  if (!user) return res.status(404).json({ error: 'User not found' });

  res.json(user);
});

// ---------------------------------------------------------------------------
// POST /users
// Validates: name (required, string, 1-100 chars),
//            email (required, valid format, max 254 chars).
// ---------------------------------------------------------------------------
app.post('/users', (req, res) => {
  const { valid, errors } = validateCreateUser(req.body);
  if (!valid) return sendValidationError(res, errors);

  const user = { id: nextId++, name: req.body.name, email: req.body.email };
  users.push(user);
  res.status(201).json(user);
});

// ---------------------------------------------------------------------------
// PUT /users/:id
// Validates: id is a positive integer,
//            at least one of name / email present,
//            name (if given): string, 1-100 chars,
//            email (if given): valid format, max 254 chars.
// ---------------------------------------------------------------------------
app.put('/users/:id', (req, res) => {
  const idCheck = validateIdParam(req.params.id);
  const bodyCheck = validateUpdateUser(req.body);

  const errors = [...idCheck.errors, ...bodyCheck.errors];
  if (errors.length > 0) return sendValidationError(res, errors);

  const user = users.find((u) => u.id === Number(req.params.id));
  if (!user) return res.status(404).json({ error: 'User not found' });

  if (req.body.name != null) user.name = req.body.name;
  if (req.body.email != null) user.email = req.body.email;

  res.json(user);
});

// ---------------------------------------------------------------------------
// DELETE /users/:id
// Validates: id is a positive integer.
// ---------------------------------------------------------------------------
app.delete('/users/:id', (req, res) => {
  const { valid, errors } = validateIdParam(req.params.id);
  if (!valid) return sendValidationError(res, errors);

  const index = users.findIndex((u) => u.id === Number(req.params.id));
  if (index === -1) return res.status(404).json({ error: 'User not found' });

  const [deleted] = users.splice(index, 1);
  res.json(deleted);
});

// ---------------------------------------------------------------------------
app.listen(3000, () => {
  console.log('Server running on port 3000');
});

module.exports = app;

