21	let nextId = 3;
22	
23	// ---------------------------------------------------------------------------
24	// Helper — send a 400 with the full list of validation errors
25	// ---------------------------------------------------------------------------
26	function sendValidationError(res, errors) {
27	  return res.status(400).json({ error: 'Validation failed', details: errors });
28	}
29	
30	// ---------------------------------------------------------------------------
31	// GET /health — no input to validate
32	// ---------------------------------------------------------------------------
33	app.get('/health', (req, res) => {
34	  res.json({ status: 'ok', timestamp: new Date().toISOString() });
35	});
36	
37	// ---------------------------------------------------------------------------
38	// GET /users — no input to validate
39	// Returns the full list of users.
40	// ---------------------------------------------------------------------------
41	app.get('/users', (req, res) => {
42	  res.json(users);
43	});
44	
45	// ---------------------------------------------------------------------------
46	// GET /users/:id
47	// Validates: id is a positive integer.
48	// ---------------------------------------------------------------------------
49	app.get('/users/:id', (req, res) => {
50	  const { valid, errors } = validateIdParam(req.params.id);
51	  if (!valid) return sendValidationError(res, errors);
52	
53	  const user = users.find((u) => u.id === Number(req.params.id));
54	  if (!user) return res.status(404).json({ error: 'User not found' });
55	
56	  res.json(user);
57	});
58	
59	// ---------------------------------------------------------------------------
60	// POST /users
61	// Validates: name (required, string, 1-100 chars),
62	//            email (required, valid format, max 254 chars).
63	// ---------------------------------------------------------------------------
64	app.post('/users', (req, res) => {
65	  const { valid, errors } = validateCreateUser(req.body);
66	  if (!valid) return sendValidationError(res, errors);
67	
68	  const user = { id: nextId++, name: req.body.name, email: req.body.email };
69	  users.push(user);
70	  res.status(201).json(user);
71	});
72	
73	// ---------------------------------------------------------------------------
74	// PUT /users/:id
75	// Validates: id is a positive integer,
76	//            at least one of name / email present,
77	//            name (if given): string, 1-100 chars,
78	//            email (if given): valid format, max 254 chars.
79	// ---------------------------------------------------------------------------
80	app.put('/users/:id', (req, res) => {
81	  const idCheck = validateIdParam(req.params.id);
82	  const bodyCheck = validateUpdateUser(req.body);
83	
84	  const errors = [...idCheck.errors, ...bodyCheck.errors];
85	  if (errors.length > 0) return sendValidationError(res, errors);
86	
87	  const user = users.find((u) => u.id === Number(req.params.id));
88	  if (!user) return res.status(404).json({ error: 'User not found' });
89	
90	  if (req.body.name != null) user.name = req.body.name;
91	  if (req.body.email != null) user.email = req.body.email;
92	
93	  res.json(user);
94	});
95	
96	// ---------------------------------------------------------------------------
97	// DELETE /users/:id
98	// Validates: id is a positive integer.
99	// ---------------------------------------------------------------------------
100	app.delete('/users/:id', (req, res) => {
101	  const { valid, errors } = validateIdParam(req.params.id);
102	  if (!valid) return sendValidationError(res, errors);
103	
104	  const index = users.findIndex((u) => u.id === Number(req.params.id));
105	  if (index === -1) return res.status(404).json({ error: 'User not found' });
106	
107	  const [deleted] = users.splice(index, 1);
108	  res.json(deleted);
109	});
110	
111	// ---------------------------------------------------------------------------
112	app.listen(3000, () => {
113	  console.log('Server running on port 3000');
114	});
115	
116	module.exports = app;
