1	/**
2	 * Validation helper module.
3	 * Each helper returns { valid: boolean, errors: string[] } so route handlers
4	 * can collect all failures in one pass and return them together.
5	 */
6	
7	// ---------------------------------------------------------------------------
8	// Primitive validators — return an array of error strings (empty = valid)
9	// ---------------------------------------------------------------------------
10	
11	/**
12	 * Validates a value is a string whose length sits within [minLen, maxLen].
13	 */
14	function validateString(value, fieldName, minLen = 1, maxLen = Infinity) {
15	  const errors = [];
16	  if (typeof value !== 'string') {
17	    errors.push(`${fieldName} must be a string`);
18	    return errors; // length checks are meaningless if the type is wrong
19	  }
20	  if (value.length < minLen) {
21	    errors.push(`${fieldName} must be at least ${minLen} character(s) long`);
22	  }
23	  if (value.length > maxLen) {
24	    errors.push(`${fieldName} must be at most ${maxLen} character(s) long`);
25	  }
26	  return errors;
27	}
28	
29	/**
30	 * Validates a value (or a string representation of one) is a positive integer.
31	 * Accepts both numeric types and the string equivalents that arrive as URL params.
32	 */
33	function validateNumericId(value, fieldName = 'id') {
34	  const num = Number(value);
35	  if (!Number.isInteger(num) || num <= 0) {
36	    return [`${fieldName} must be a positive integer`];
37	  }
38	  return [];
39	}
40	
41	/**
42	 * Validates a value is a properly formatted email address (RFC 5321 max 254 chars).
43	 */
44	function validateEmail(value, fieldName = 'email') {
45	  const errors = [];
46	  if (typeof value !== 'string') {
47	    errors.push(`${fieldName} must be a string`);
48	    return errors;
49	  }
50	  // Simple but effective pattern: local@domain.tld, no whitespace or double-@
51	  const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
52	  if (!EMAIL_RE.test(value)) {
53	    errors.push(`${fieldName} must be a valid email address`);
54	  }
55	  if (value.length > 254) {
56	    errors.push(`${fieldName} must be at most 254 character(s) long`);
57	  }
58	  return errors;
59	}
60	
61	// ---------------------------------------------------------------------------
62	// Composite validators — used directly in route handlers
63	// ---------------------------------------------------------------------------
64	
65	/**
66	 * Validates a URL :id parameter.
67	 *
68	 * Rules:
69	 *  - Required
70	 *  - Must be a positive integer
71	 *
72	 * @param {string} param  Raw value from req.params
73	 * @param {string} [fieldName]
74	 * @returns {{ valid: boolean, errors: string[] }}
75	 */
76	function validateIdParam(param, fieldName = 'id') {
77	  const errors = validateNumericId(param, fieldName);
78	  return { valid: errors.length === 0, errors };
79	}
80	
81	/**
82	 * Validates the request body for POST /users (user creation).
83	 *
84	 * Rules:
85	 *  - name: required, string, 1–100 chars
86	 *  - email: required, valid email format, max 254 chars
87	 *
88	 * @param {object} body  req.body
89	 * @returns {{ valid: boolean, errors: string[] }}
90	 */
91	function validateCreateUser(body) {
92	  const errors = [];
93	
94	  if (body.name == null) {
95	    errors.push('name is required');
96	  } else {
97	    errors.push(...validateString(body.name, 'name', 1, 100));
98	  }
99	
100	  if (body.email == null) {
101	    errors.push('email is required');
102	  } else {
103	    errors.push(...validateEmail(body.email, 'email'));
104	  }
105	
106	  return { valid: errors.length === 0, errors };
107	}
108	
109	/**
110	 * Validates the request body for PUT /users/:id (user update).
111	 *
112	 * Rules:
113	 *  - At least one of name or email must be supplied
114	 *  - name (if present): string, 1–100 chars
115	 *  - email (if present): valid email format, max 254 chars
116	 *
117	 * @param {object} body  req.body
118	 * @returns {{ valid: boolean, errors: string[] }}
119	 */
120	function validateUpdateUser(body) {
121	  const errors = [];
122	
123	  const hasName = body.name != null;
124	  const hasEmail = body.email != null;
125	
126	  if (!hasName && !hasEmail) {
127	    errors.push('at least one field (name or email) must be provided');
128	  }
129	
130	  if (hasName) {
131	    errors.push(...validateString(body.name, 'name', 1, 100));
132	  }
133	
134	  if (hasEmail) {
135	    errors.push(...validateEmail(body.email, 'email'));
136	  }
137	
138	  return { valid: errors.length === 0, errors };
139	}
140	
141	module.exports = {
142	  validateIdParam,
143	  validateCreateUser,
144	  validateUpdateUser,
145	  // Export primitives so they can be unit-tested or reused in other modules
146	  _validateString: validateString,
147	  _validateNumericId: validateNumericId,
148	  _validateEmail: validateEmail,
149	};
